// STRATEGY : Ultimate Confluence Strategy v2.0
// AUTHOR   : AI-Generated | Pine Script v5
// MARKETS  : Crypto, Forex, Indices, Stocks
// TIMEFRAME: 15m, 1H, 4H (recommended)
//
// ─── LOGIC OVERVIEW ─────────────────────────────────────────────
// BUY  = EMA Trend UP + RSI oversold recovery + MACD bullish
//         + SuperTrend green + Volume confirmation
// SELL = EMA Trend DOWN + RSI overbought rejection + MACD bearish
//         + SuperTrend red + Volume confirmation
//
// TP = ATR-based dynamic take-profit (2 levels: TP1, TP2)
// SL = ATR-based dynamic stop-loss below/above structure
//
// ─── WHAT WORKS ─────────────────────────────────────────────────
// ✓ Multi-indicator confluence = fewer false signals
// ✓ ATR-based SL/TP adapts to volatility automatically
// ✓ Volume filter removes low-conviction signals
// ✓ SuperTrend keeps you on the right side of trend
// ✓ EMA stack confirms higher-timeframe bias
//
// ─── WHAT TO WATCH OUT FOR ──────────────────────────────────────
// ✗ Choppy/sideways markets — use ADX filter (built in)
// ✗ News events can spike through TP/SL — reduce size
// ✗ Do NOT use on 1m chart — too much noise
// ✗ No strategy wins 100% — always use proper position sizing
// ============================================================

//@version=5
strategy(
     title            = "Ultimate Confluence Strategy v2.0",
     shorttitle        = "UCS v2.0",
     overlay           = true,
     initial_capital   = 10000,
     default_qty_type  = strategy.percent_of_equity,
     default_qty_value = 10,
     commission_type   = strategy.commission.percent,
     commission_value  = 0.05,
     slippage          = 2,
     max_bars_back     = 500
     )

// ═══════════════════════════════════════════════════════════════
//  ① INPUTS
// ═══════════════════════════════════════════════════════════════

// — EMA Settings —
emaFastLen  = input.int(21,  "Fast EMA",          group="📈 Trend (EMAs)",   minval=5)
emaMidLen   = input.int(50,  "Mid EMA",            group="📈 Trend (EMAs)",   minval=10)
emaSlowLen  = input.int(200, "Slow EMA",           group="📈 Trend (EMAs)",   minval=50)

// — RSI Settings —
rsiLen      = input.int(14,  "RSI Length",         group="⚡ Momentum (RSI)", minval=5)
rsiOB       = input.int(70,  "Overbought Level",   group="⚡ Momentum (RSI)", minval=60, maxval=90)
rsiOS       = input.int(30,  "Oversold Level",     group="⚡ Momentum (RSI)", maxval=40, minval=10)

// — MACD Settings —
macdFast    = input.int(12,  "MACD Fast",          group="📊 Momentum (MACD)")
macdSlow    = input.int(26,  "MACD Slow",          group="📊 Momentum (MACD)")
macdSignal  = input.int(9,   "MACD Signal",        group="📊 Momentum (MACD)")

// — SuperTrend Settings —
stAtrLen    = input.int(10,  "ATR Length",         group="🌊 SuperTrend",    minval=5)
stFactor    = input.float(3.0,"Factor",            group="🌊 SuperTrend",    minval=1.0, step=0.5)

// — ATR for TP/SL —
atrLen      = input.int(14,  "ATR Length (SL/TP)", group="🎯 Risk Management")
slMult      = input.float(1.5,"SL ATR Multiplier", group="🎯 Risk Management", minval=0.5, step=0.25)
tp1Mult     = input.float(2.0,"TP1 ATR Multiplier",group="🎯 Risk Management", minval=0.5, step=0.25)
tp2Mult     = input.float(4.0,"TP2 ATR Multiplier",group="🎯 Risk Management", minval=1.0, step=0.5)

// — ADX Filter (avoids choppy market) —
useAdx      = input.bool(true,"Use ADX Filter",    group="🔍 Filters")
adxLen      = input.int(14,  "ADX Length",         group="🔍 Filters",       minval=5)
adxThresh   = input.int(20,  "Min ADX Strength",   group="🔍 Filters",       minval=10, maxval=40)

// — Volume Filter —
useVol      = input.bool(true,"Use Volume Filter",  group="🔍 Filters")
volLen      = input.int(20,  "Volume MA Length",   group="🔍 Filters",       minval=5)

// — Trade Direction —
tradeDir    = input.string("Both","Trade Direction", group="⚙️ Settings",
             options=["Both","Long Only","Short Only"])

// — Date Range —
startDate   = input.time(timestamp("2022-01-01"),"Start Date", group="📅 Backtest Range")
endDate     = input.time(timestamp("2030-12-31"),"End Date",   group="📅 Backtest Range")
inDateRange = time >= startDate and time <= endDate

// ═══════════════════════════════════════════════════════════════
//  ② INDICATOR CALCULATIONS
// ═══════════════════════════════════════════════════════════════

// — EMAs —
emaFast = ta.ema(close, emaFastLen)
emaMid  = ta.ema(close, emaMidLen)
emaSlow = ta.ema(close, emaSlowLen)

// — RSI —
rsi     = ta.rsi(close, rsiLen)

// — MACD —
[macdLine, signalLine, histLine] = ta.macd(close, macdFast, macdSlow, macdSignal)
macdBull = macdLine > signalLine
macdBear = macdLine < signalLine
macdCrossBull = ta.crossover(macdLine, signalLine)
macdCrossBear = ta.crossunder(macdLine, signalLine)

// — SuperTrend —
[superTrend, stDirection] = ta.supertrend(stFactor, stAtrLen)
stBull = stDirection < 0  // price above supertrend = bullish
stBear = stDirection > 0  // price below supertrend = bearish

// — ATR for SL/TP —
atrVal = ta.atr(atrLen)

// — ADX Calculation —
[diPlus, diMinus, adxVal] = ta.dmi(adxLen, adxLen)
trendStrong = not useAdx or adxVal > adxThresh

// — Volume Filter —
volMA   = ta.sma(volume, volLen)
volOk   = not useVol or volume > volMA

// ═══════════════════════════════════════════════════════════════
//  ③ SIGNAL CONDITIONS
// ═══════════════════════════════════════════════════════════════

// Trend Bias
bullTrend = emaFast > emaMid and emaMid > emaSlow     // full bull stack
bearTrend = emaFast < emaMid and emaMid < emaSlow     // full bear stack

// RSI Conditions
rsiRecovery    = ta.crossover(rsi, rsiOS)             // RSI coming out of oversold
rsiRejection   = ta.crossunder(rsi, rsiOB)            // RSI coming out of overbought
rsiBullZone    = rsi > 45 and rsi < rsiOB             // RSI in healthy bull zone
rsiBearZone    = rsi < 55 and rsi > rsiOS             // RSI in healthy bear zone

// ─── BUY SIGNAL ─────────────────────────────────────────────
// All 5 conditions must align:
//  1. EMA stack bullish
//  2. RSI recovering from oversold OR in healthy bull zone + MACD crosses bull
//  3. MACD bullish cross
//  4. SuperTrend bullish (green)
//  5. Volume above average + ADX showing trend strength
buySignal = bullTrend
         and (rsiRecovery or (rsiBullZone and macdCrossBull))
         and macdBull
         and stBull
         and trendStrong
         and volOk
         and (tradeDir == "Both" or tradeDir == "Long Only")
         and inDateRange

// ─── SELL SIGNAL ─────────────────────────────────────────────
// All 5 conditions must align:
//  1. EMA stack bearish
//  2. RSI rejecting from overbought OR in healthy bear zone + MACD crosses bear
//  3. MACD bearish cross
//  4. SuperTrend bearish (red)
//  5. Volume above average + ADX showing trend strength
sellSignal = bearTrend
          and (rsiRejection or (rsiBearZone and macdCrossBear))
          and macdBear
          and stBear
          and trendStrong
          and volOk
          and (tradeDir == "Both" or tradeDir == "Short Only")
          and inDateRange

// ═══════════════════════════════════════════════════════════════
//  ④ STOP LOSS & TAKE PROFIT
// ═══════════════════════════════════════════════════════════════

// Dynamic ATR-based levels recalculated at each signal
longSL  = close - atrVal * slMult
longTP1 = close + atrVal * tp1Mult
longTP2 = close + atrVal * tp2Mult

shortSL  = close + atrVal * slMult
shortTP1 = close - atrVal * tp1Mult
shortTP2 = close - atrVal * tp2Mult

// ═══════════════════════════════════════════════════════════════
//  ⑤ STRATEGY EXECUTION
// ═══════════════════════════════════════════════════════════════

// Track TP2 as final exit (strategy only supports single TP natively;
// TP1 is shown visually. For split exits use qty_percent)

if buySignal and strategy.position_size == 0
    strategy.entry("Long", strategy.long)
    strategy.exit("Long Exit", "Long",
         stop  = longSL,
         limit = longTP2,
         comment = "L-Exit")

if sellSignal and strategy.position_size == 0
    strategy.entry("Short", strategy.short)
    strategy.exit("Short Exit", "Short",
         stop  = shortSL,
         limit = shortTP2,
         comment = "S-Exit")

// ═══════════════════════════════════════════════════════════════
//  ⑥ PLOTTING — INDICATORS
// ═══════════════════════════════════════════════════════════════

// — EMAs —
plot(emaFast,  "EMA 21",  color=color.new(color.aqua,   10), linewidth=1)
plot(emaMid,   "EMA 50",  color=color.new(color.orange,  10), linewidth=2)
plot(emaSlow,  "EMA 200", color=color.new(color.white,   10), linewidth=2)

// — SuperTrend —
superTrendColor = stBull ? color.new(color.lime, 0) : color.new(color.red, 0)
plot(superTrend, "SuperTrend", color=superTrendColor, linewidth=2, style=plot.style_line)

// ═══════════════════════════════════════════════════════════════
//  ⑦ SIGNAL LABELS — BUY / SELL
// ═══════════════════════════════════════════════════════════════

plotshape(buySignal,
     title    = "BUY",
     location = location.belowbar,
     style    = shape.labelup,
     size     = size.normal,
     color    = color.new(color.lime, 0),
     textcolor= color.black,
     text     = "BUY")

plotshape(sellSignal,
     title    = "SELL",
     location = location.abovebar,
     style    = shape.labeldown,
     size     = size.normal,
     color    = color.new(color.red, 0),
     textcolor= color.white,
     text     = "SELL")

// ═══════════════════════════════════════════════════════════════
//  ⑧ TP / SL LEVEL LINES (drawn on signal bar)
// ═══════════════════════════════════════════════════════════════

// Long levels
if buySignal
    // SL Line
    line.new(bar_index, longSL,  bar_index + 15, longSL,
         color=color.red,    width=2, style=line.style_dashed)
    // TP1 Line
    line.new(bar_index, longTP1, bar_index + 15, longTP1,
         color=color.yellow, width=1, style=line.style_dashed)
    // TP2 Line
    line.new(bar_index, longTP2, bar_index + 15, longTP2,
         color=color.lime,   width=2, style=line.style_dashed)
    // Labels
    label.new(bar_index + 8, longSL,  "🛑 SL",  style=label.style_label_left, color=color.new(color.red,80),    textcolor=color.red,    size=size.small)
    label.new(bar_index + 8, longTP1, "🎯 TP1", style=label.style_label_left, color=color.new(color.yellow,80), textcolor=color.yellow, size=size.small)
    label.new(bar_index + 8, longTP2, "🏆 TP2", style=label.style_label_left, color=color.new(color.lime,80),   textcolor=color.lime,   size=size.small)

// Short levels
if sellSignal
    // SL Line
    line.new(bar_index, shortSL,  bar_index + 15, shortSL,
         color=color.red,    width=2, style=line.style_dashed)
    // TP1 Line
    line.new(bar_index, shortTP1, bar_index + 15, shortTP1,
         color=color.yellow, width=1, style=line.style_dashed)
    // TP2 Line
    line.new(bar_index, shortTP2, bar_index + 15, shortTP2,
         color=color.lime,   width=2, style=line.style_dashed)
    // Labels
    label.new(bar_index + 8, shortSL,  "🛑 SL",  style=label.style_label_left, color=color.new(color.red,80),    textcolor=color.red,    size=size.small)
    label.new(bar_index + 8, shortTP1, "🎯 TP1", style=label.style_label_left, color=color.new(color.yellow,80), textcolor=color.yellow, size=size.small)
    label.new(bar_index + 8, shortTP2, "🏆 TP2", style=label.style_label_left, color=color.new(color.lime,80),   textcolor=color.lime,   size=size.small)

// ═══════════════════════════════════════════════════════════════
//  ⑨ BACKGROUND TREND COLORING
// ═══════════════════════════════════════════════════════════════

bgColor = bullTrend and stBull ? color.new(color.lime, 93) :
          bearTrend and stBear ? color.new(color.red,  93) :
          color.new(color.gray, 97)

bgcolor(bgColor, title="Trend Background")

// ═══════════════════════════════════════════════════════════════
//  ⑩ INFO TABLE (top-right dashboard)
// ═══════════════════════════════════════════════════════════════

var table infoTable = table.new(position.top_right, 2, 8,
     bgcolor=color.new(color.black, 70), border_color=color.new(color.gray,50), border_width=1)

if barstate.islast
    // Header
    table.cell(infoTable, 0, 0, "UCS v2.0",    text_color=color.white, bgcolor=color.new(color.blue,40), text_size=size.small)
    table.cell(infoTable, 1, 0, "Status",       text_color=color.white, bgcolor=color.new(color.blue,40), text_size=size.small)

    // Trend
    trendText  = bullTrend ? "🟢 BULL" : bearTrend ? "🔴 BEAR" : "⚪ CHOP"
    trendColor = bullTrend ? color.lime : bearTrend ? color.red : color.gray
    table.cell(infoTable, 0, 1, "Trend",        text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 1, trendText,      text_color=trendColor,   text_size=size.small)

    // SuperTrend
    stText  = stBull ? "🟢 Bullish" : "🔴 Bearish"
    stColor = stBull ? color.lime : color.red
    table.cell(infoTable, 0, 2, "SuperTrend",   text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 2, stText,         text_color=stColor,      text_size=size.small)

    // RSI
    rsiText  = rsi > rsiOB ? "🔴 Overbought" : rsi < rsiOS ? "🟢 Oversold" : "⚪ Neutral"
    rsiColor = rsi > rsiOB ? color.red : rsi < rsiOS ? color.lime : color.gray
    table.cell(infoTable, 0, 3, "RSI (" + str.tostring(rsiLen) + ")", text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 3, rsiText + " " + str.tostring(math.round(rsi, 1)), text_color=rsiColor, text_size=size.small)

    // MACD
    macdText  = macdBull ? "🟢 Bullish" : "🔴 Bearish"
    macdColor = macdBull ? color.lime : color.red
    table.cell(infoTable, 0, 4, "MACD",         text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 4, macdText,        text_color=macdColor,    text_size=size.small)

    // ADX
    adxText  = adxVal > adxThresh ? "✅ Trending" : "⚠️ Weak"
    adxColor = adxVal > adxThresh ? color.lime : color.orange
    table.cell(infoTable, 0, 5, "ADX",          text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 5, adxText + " " + str.tostring(math.round(adxVal, 1)), text_color=adxColor, text_size=size.small)

    // ATR
    table.cell(infoTable, 0, 6, "ATR",          text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 6, str.tostring(math.round(atrVal, 4)), text_color=color.white, text_size=size.small)

    // Position
    posText  = strategy.position_size > 0 ? "📈 LONG" : strategy.position_size < 0 ? "📉 SHORT" : "💤 FLAT"
    posColor = strategy.position_size > 0 ? color.lime : strategy.position_size < 0 ? color.red : color.gray
    table.cell(infoTable, 0, 7, "Position",     text_color=color.silver, text_size=size.small)
    table.cell(infoTable, 1, 7, posText,         text_color=posColor,     text_size=size.small)

// ═══════════════════════════════════════════════════════════════
//  ⑪ ALERTS
// ═══════════════════════════════════════════════════════════════

alertcondition(buySignal,  title="🟢 BUY Signal",  message="UCS v2.0 — BUY Signal on {{ticker}} @ {{close}} | SL: {{plot_0}} | TP1: {{plot_1}} | TP2: {{plot_2}}")
alertcondition(sellSignal, title="🔴 SELL Signal", message="UCS v2.0 — SELL Signal on {{ticker}} @ {{close}} | SL: {{plot_0}} | TP1: {{plot_1}} | TP2: {{plot_2}}")

